#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int dp[51][51][2601];
int main() {
    int N;
    scanf("%d", &N);
    int B[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &B[i]);
    }
    dp[0][0][0] = 1;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j <= i; j++) {
            for (int k = 0; k <= 50 * N; k++) {
                if (dp[i][j][k] == 0) continue;
                for (int l = 0; l <= B[i]; l++) {
                    int nj = j + (l == 0);
                    int nk = k + l;
                    dp[i + 1][nj][nk] = (dp[i + 1][nj][nk] + dp[i][j][k]) % MOD;
                }
            }
        }
    }
    printf("%d\n", dp[N][N - 1][0]);
    return 0;
}

