    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] B = new int[N];
        for (int i = 0; i < N; i++) {
            B[i] = sc.nextInt();
        }
        int[][][] dp = new int[N + 1][N + 1][51 * N + 1];
        dp[0][0][0] = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j <= i; j++) {
                for (int k = 0; k <= 50 * N; k++) {
                    if (dp[i][j][k] == 0) continue;
                    for (int l = 0; l <= B[i]; l++) {
                        int nj = j + (l == 0);
                        int nk = k + l;
                        dp[i + 1][nj][nk] = (dp[i + 1][nj][nk] + dp[i][j][k]) % MOD;
